/**
 * Public output of the Production Kernel.
 * It aggregates all artifacts produced by the execution together with
 * execution status information, warnings, errors, metrics and total duration.
 * This single contract guarantees that downstream layers receive a complete
 * description of what happened without having to query multiple sources.
 */
export interface ExecutionResult {
  /** Identifier of the execution plan that produced this result */
  readonly executionId: string;

  /** Overall status of the execution */
  readonly status: ExecutionStatus;

  /** Artifacts generated by the execution (e.g., APK, image, document) */
  readonly artifacts: readonly Artifact[];

  /** Non‑critical warnings that occurred during execution */
  readonly warnings?: readonly string[];

  /** Errors that prevented successful completion (if any) */
  readonly errors?: readonly string[];

  /** Optional metrics collected during execution */
  readonly metrics?: Record<string, unknown>;

  /** Total duration in milliseconds */
  readonly durationMs: number;
}

/** Simple enumeration of possible execution outcomes */
export enum ExecutionStatus {
  SUCCESS = "success",
  PARTIAL_SUCCESS = "partial_success",
  FAILURE = "failure",
}

/** Generic artifact descriptor */
export interface Artifact {
  /** Type of artifact, e.g. "apk", "image", "video", "document" */
  readonly type: string;
  /** Payload can be any serialisable data – a Buffer, JSON, URL, etc. */
  readonly payload: unknown;
}
